import sys
from collections import deque

class Queue:
    def __init__(self):
        self.queue = deque()

    def isEmpty(self):
        return len(self.queue) == 0

    def enqueue(self, val):
        self.queue.append(val)

    def dequeue(self):
        if self.isEmpty():
            raise IndexError('pop from an empty list')
        return self.queue.popleft()

n = int(input().split()[0])
queue = Queue()
for _ in range(n):
    queue.enqueue(int(input().split()[0]))

print(' '.join(map(str, [queue.dequeue() for _ in range(n-1)])))

