#include <iostream>
using namespace std;
class Node {
public:
    int val;
    Node* next;
    Node(int val) {
        this->val = val;
        this->next = nullptr;
    }
};
class Queue {
public:
    Node* head;
    bool isEmpty();
    void enqueue(int val);
    int dequeue();
};
bool Queue::isEmpty() {
    return head == nullptr;
}
void Queue::enqueue(int val) {
    Node* node = new Node(val);
    if (head == nullptr)
        head = node;
    else
        Node* current = head;
        while (current->next != nullptr)
            current = current->next;
        current->next = node;
}
int Queue::dequeue() {
    if (head == nullptr)
        throw runtime_error("pop from an empty list");
    int val = head->val;
    Node* temp = head;
    head = head->next;
    delete temp;
    return val;
}
int main() {
    int n;
    cin >> n;
    Queue queue;
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        queue.enqueue(val);
    }
    for (int i = 0; i < n - 1; i++) {
        cout << queue.dequeue() << ' ';
    }
    cout << '
';
    return 0;
}
